+/**
+ * Webhook handler — dispatches HTTP POST callbacks to registered URLs
+ * when order lifecycle events occur via EventBus subscriptions.
+ *
+ * Follows the same EventBus-driven pattern as NotificationService
+ * and EmailNotificationHandler. See decision record in .twining/.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving order events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type {
+  AppEvent,
+  EventType,
+  OrderCreatedEvent,
+  OrderStatusChangedEvent,
+} from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookRegistration {
+  id: string;
+  url: string;
+  eventTypes: EventType[];
+  secret?: string;
+  active: boolean;
+  createdAt: Date;
+}
+
+export interface WebhookDelivery {
+  id: string;
+  webhookId: string;
+  url: string;
+  eventType: EventType;
+  payload: WebhookPayload;
+  success: boolean;
+  deliveredAt: Date;
+}
+
+export interface WebhookPayload {
+  event: EventType;
+  timestamp: string;
+  data: Record<string, unknown>;
+}
+
+let nextWebhookId = 1;
+let nextDeliveryId = 1;
+
+function generateWebhookId(): string {
+  return `wh-${String(nextWebhookId++).padStart(4, '0')}`;
+}
+
+function generateDeliveryId(): string {
+  return `whd-${String(nextDeliveryId++).padStart(4, '0')}`;
+}
+
+export function resetWebhookIdCounters(): void {
+  nextWebhookId = 1;
+  nextDeliveryId = 1;
+}
+
+export class WebhookHandler {
+  private logger = new Logger('WebhookHandler');
+  private registrations: WebhookRegistration[] = [];
+  private deliveries: WebhookDelivery[] = [];
+  private httpSender: (url: string, payload: WebhookPayload, secret?: string) => Promise<boolean>;
+
+  constructor(
+    private eventBus: EventBus,
+    httpSender?: (url: string, payload: WebhookPayload, secret?: string) => Promise<boolean>,
+  ) {
+    // Default sender simulates successful delivery (in-memory for this demo)
+    this.httpSender = httpSender ?? (async () => true);
+    this.registerHandlers();
+  }
+
+  /**
+   * Register EventBus handlers for order events that may trigger webhooks.
+   */
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      return this.dispatchWebhooks(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      return this.dispatchWebhooks(event);
+    });
+  }
+
+  /**
+   * Register a webhook URL for specific event types.
+   */
+  registerWebhook(params: {
+    url: string;
+    eventTypes: EventType[];
+    secret?: string;
+  }): WebhookRegistration {
+    const registration: WebhookRegistration = {
+      id: generateWebhookId(),
+      url: params.url,
+      eventTypes: params.eventTypes,
+      secret: params.secret,
+      active: true,
+      createdAt: new Date(),
+    };
+    this.registrations.push(registration);
+    this.logger.info(
+      `Webhook registered: ${registration.id} -> ${params.url} for [${params.eventTypes.join(', ')}]`,
+    );
+    return registration;
+  }
+
+  /**
+   * Unregister a webhook by ID.
+   */
+  unregisterWebhook(id: string): boolean {
+    const index = this.registrations.findIndex((r) => r.id === id);
+    if (index >= 0) {
+      this.registrations.splice(index, 1);
+      this.logger.info(`Webhook unregistered: ${id}`);
+      return true;
+    }
+    return false;
+  }
+
+  /**
+   * Deactivate a webhook without removing it.
+   */
+  deactivateWebhook(id: string): boolean {
+    const registration = this.registrations.find((r) => r.id === id);
+    if (registration) {
+      registration.active = false;
+      this.logger.info(`Webhook deactivated: ${id}`);
+      return true;
+    }
+    return false;
+  }
+
+  /**
+   * Activate a previously deactivated webhook.
+   */
+  activateWebhook(id: string): boolean {
+    const registration = this.registrations.find((r) => r.id === id);
+    if (registration) {
+      registration.active = true;
+      this.logger.info(`Webhook activated: ${id}`);
+      return true;
+    }
+    return false;
+  }
+
+  /**
+   * Dispatch webhooks for a given event to all matching registered URLs.
+   */
+  private async dispatchWebhooks(event: AppEvent): Promise<void> {
+    const matching = this.registrations.filter(
+      (r) => r.active && r.eventTypes.includes(event.type),
+    );
+
+    if (matching.length === 0) {
+      return;
+    }
+
+    const payload = this.buildPayload(event);
+
+    for (const registration of matching) {
+      const success = await this.httpSender(registration.url, payload, registration.secret);
+
+      const delivery: WebhookDelivery = {
+        id: generateDeliveryId(),
+        webhookId: registration.id,
+        url: registration.url,
+        eventType: event.type,
+        payload,
+        success,
+        deliveredAt: new Date(),
+      };
+      this.deliveries.push(delivery);
+
+      if (success) {
+        this.logger.info(`Webhook delivered: ${delivery.id} to ${registration.url}`);
+      } else {
+        this.logger.info(`Webhook delivery failed: ${delivery.id} to ${registration.url}`);
+      }
+    }
+  }
+
+  /**
+   * Build a webhook payload from an event.
+   */
+  private buildPayload(event: AppEvent): WebhookPayload {
+    const { type, timestamp, ...data } = event;
+    return {
+      event: type,
+      timestamp: timestamp.toISOString(),
+      data: data as Record<string, unknown>,
+    };
+  }
+
+  /**
+   * Get all registered webhooks.
+   */
+  getRegistrations(): WebhookRegistration[] {
+    return [...this.registrations];
+  }
+
+  /**
+   * Get a webhook registration by ID.
+   */
+  getRegistration(id: string): WebhookRegistration | undefined {
+    return this.registrations.find((r) => r.id === id);
+  }
+
+  /**
+   * Get all delivery records.
+   */
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  /**
+   * Get delivery records for a specific webhook.
+   */
+  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.webhookId === webhookId);
+  }
+
+  /**
+   * Get the count of deliveries.
+   */
+  getDeliveryCount(): number {
+    return this.deliveries.length;
+  }
+
+  /**
+   * Clear all registrations and deliveries (useful for testing).
+   */
+  clear(): void {
+    this.registrations = [];
+    this.deliveries = [];
+  }
+}

