/**
 * Webhook handler — dispatches HTTP POST callbacks to registered URLs
 * when order lifecycle events occur via EventBus subscriptions.
 *
 * Follows the same EventBus-driven pattern as NotificationService
 * and EmailNotificationHandler. See decision record in .twining/.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  AppEvent,
  EventType,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventTypes: EventType[];
  secret?: string;
  active: boolean;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `wh-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `whd-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpSender: (url: string, payload: WebhookPayload, secret?: string) => Promise<boolean>;

  constructor(
    private eventBus: EventBus,
    httpSender?: (url: string, payload: WebhookPayload, secret?: string) => Promise<boolean>,
  ) {
    // Default sender simulates successful delivery (in-memory for this demo)
    this.httpSender = httpSender ?? (async () => true);
    this.registerHandlers();
  }

  /**
   * Register EventBus handlers for order events that may trigger webhooks.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.dispatchWebhooks(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.dispatchWebhooks(event);
    });
  }

  /**
   * Register a webhook URL for specific event types.
   */
  registerWebhook(params: {
    url: string;
    eventTypes: EventType[];
    secret?: string;
  }): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url: params.url,
      eventTypes: params.eventTypes,
      secret: params.secret,
      active: true,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(
      `Webhook registered: ${registration.id} -> ${params.url} for [${params.eventTypes.join(', ')}]`,
    );
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Deactivate a webhook without removing it.
   */
  deactivateWebhook(id: string): boolean {
    const registration = this.registrations.find((r) => r.id === id);
    if (registration) {
      registration.active = false;
      this.logger.info(`Webhook deactivated: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Activate a previously deactivated webhook.
   */
  activateWebhook(id: string): boolean {
    const registration = this.registrations.find((r) => r.id === id);
    if (registration) {
      registration.active = true;
      this.logger.info(`Webhook activated: ${id}`);
      return true;
    }
    return false;
  }

  /**
   * Dispatch webhooks for a given event to all matching registered URLs.
   */
  private async dispatchWebhooks(event: AppEvent): Promise<void> {
    const matching = this.registrations.filter(
      (r) => r.active && r.eventTypes.includes(event.type),
    );

    if (matching.length === 0) {
      return;
    }

    const payload = this.buildPayload(event);

    for (const registration of matching) {
      const success = await this.httpSender(registration.url, payload, registration.secret);

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType: event.type,
        payload,
        success,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);

      if (success) {
        this.logger.info(`Webhook delivered: ${delivery.id} to ${registration.url}`);
      } else {
        this.logger.info(`Webhook delivery failed: ${delivery.id} to ${registration.url}`);
      }
    }
  }

  /**
   * Build a webhook payload from an event.
   */
  private buildPayload(event: AppEvent): WebhookPayload {
    const { type, timestamp, ...data } = event;
    return {
      event: type,
      timestamp: timestamp.toISOString(),
      data: data as Record<string, unknown>,
    };
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get a webhook registration by ID.
   */
  getRegistration(id: string): WebhookRegistration | undefined {
    return this.registrations.find((r) => r.id === id);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get delivery records for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook.handler.js';
import type { WebhookPayload } from '../../src/notifications/webhook.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;
  let mockSender: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    resetWebhookIdCounters();
    eventBus = new EventBus();
    mockSender = vi.fn().mockResolvedValue(true);
    handler = new WebhookHandler(eventBus, mockSender);
  });

  const makeOrderCreatedEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-01T00:00:00Z'),
  });

  const makeStatusEvent = (
    previousStatus: string,
    newStatus: string,
  ): OrderStatusChangedEvent => ({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: newStatus as OrderStatusChangedEvent['order']['status'],
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date('2026-01-01T00:00:00Z'),
  });

  describe('webhook registration', () => {
    it('should register a webhook and return registration', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(reg.id).toBe('wh-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventTypes).toEqual(['order:created']);
      expect(reg.active).toBe(true);
    });

    it('should register multiple webhooks with unique IDs', () => {
      const reg1 = handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      const reg2 = handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:status-changed'],
      });

      expect(reg1.id).toBe('wh-0001');
      expect(reg2.id).toBe('wh-0002');
    });

    it('should store secret when provided', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      expect(reg.secret).toBe('my-secret');
    });

    it('should list all registrations', () => {
      handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:status-changed'],
      });

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should get a registration by ID', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.getRegistration(reg.id)?.url).toBe('https://example.com/hook');
      expect(handler.getRegistration('nonexistent')).toBeUndefined();
    });

    it('should unregister a webhook', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering nonexistent webhook', () => {
      expect(handler.unregisterWebhook('nonexistent')).toBe(false);
    });
  });

  describe('webhook activation', () => {
    it('should deactivate a webhook', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.deactivateWebhook(reg.id)).toBe(true);
      expect(handler.getRegistration(reg.id)?.active).toBe(false);
    });

    it('should reactivate a deactivated webhook', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      handler.deactivateWebhook(reg.id);
      expect(handler.activateWebhook(reg.id)).toBe(true);
      expect(handler.getRegistration(reg.id)?.active).toBe(true);
    });

    it('should not dispatch to deactivated webhooks', async () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      handler.deactivateWebhook(reg.id);
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSender).not.toHaveBeenCalled();
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('order:created webhook dispatch', () => {
    it('should dispatch webhook on order created', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSender).toHaveBeenCalledOnce();
      const [url, payload] = mockSender.mock.calls[0] as [string, WebhookPayload];
      expect(url).toBe('https://example.com/hook');
      expect(payload.event).toBe('order:created');
      expect(payload.timestamp).toBe('2026-01-01T00:00:00.000Z');
      expect(payload.data).toHaveProperty('order');
      expect(payload.data).toHaveProperty('user');
    });

    it('should pass secret to sender', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSender).toHaveBeenCalledWith(
        'https://example.com/hook',
        expect.any(Object),
        'my-secret',
      );
    });

    it('should not dispatch when no webhooks match event type', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSender).not.toHaveBeenCalled();
    });

    it('should dispatch to multiple matching webhooks', async () => {
      handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSender).toHaveBeenCalledTimes(2);
      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('order:status-changed webhook dispatch', () => {
    it('should dispatch webhook on status change', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(mockSender).toHaveBeenCalledOnce();
      const [, payload] = mockSender.mock.calls[0] as [string, WebhookPayload];
      expect(payload.event).toBe('order:status-changed');
      expect(payload.data).toHaveProperty('previousStatus', 'pending');
      expect(payload.data).toHaveProperty('newStatus', 'confirmed');
    });

    it('should dispatch to webhook registered for multiple event types', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(mockSender).toHaveBeenCalledTimes(2);
      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.webhookId).toBe(reg.id);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
      expect(deliveries[0]?.eventType).toBe('order:created');
      expect(deliveries[0]?.success).toBe(true);
    });

    it('should record failed deliveries', async () => {
      mockSender.mockResolvedValue(false);

      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveriesForWebhook(reg1.id);
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://a.com/hook');
    });

    it('should accumulate deliveries across events', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(2);
    });
  });

  describe('clear', () => {
    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('default sender', () => {
    it('should work with default sender (no custom sender provided)', async () => {
      const defaultHandler = new WebhookHandler(eventBus);
      defaultHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(defaultHandler.getDeliveryCount()).toBe(1);
      expect(defaultHandler.getDeliveries()[0]?.success).toBe(true);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside NotificationService and EmailNotificationHandler', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email.handler.js'
      );
      resetNotificationIdCounter();

      const sharedBus = new EventBus();
      const notifService = new NotificationService(sharedBus);
      const emailHandler = new EmailNotificationHandler(sharedBus);
      const webhookHandler = new WebhookHandler(sharedBus, mockSender);

      webhookHandler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await sharedBus.emit(makeStatusEvent('pending', 'confirmed'));

      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
      expect(webhookHandler.getDeliveryCount()).toBe(1);
    });
  });
});
